# Grupo principal
@click.group()
def git():
    """Ferramenta de controle de versão."""
    pass

# Subcomando commit
@git.command()
@click.option('-m', '--message', required=True, help='Mensagem do commit')
@click.option('--amend', is_flag=True, help='Alterar último commit')
def commit(message, amend):
    """Registra alterações no repositório."""
    if amend:
        click.secho(f'✏️  Commit alterado: {message}', fg='yellow')
    else:
        click.secho(f'✅ Commit realizado: {message}', fg='green')

# Subcomando log
@git.command()
@click.option('-n', '--limit', type=int, default=5, help='Número de commits')
@click.option('--oneline', is_flag=True, help='Formato resumido')
def log(limit, oneline):
    """Mostra histórico de commits."""
    commits = [
        'abc123 - Adiciona funcionalidade X',
        'def456 - Corrige bug Y',
        'ghi789 - Atualiza documentação'
    ]

    click.echo(f'📜 Últimos {limit} commits:\n')
    for commit in commits[:limit]:
        if oneline:
            click.echo(f'  {commit}')
        else:
            click.echo(f'  • {commit}')

if __name__ == '__main__':
    git()

import time
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

class MeuHandler(FileSystemEventHandler):
    def on_created(self, event):
        if not event.is_directory:
            print(f'📄 Arquivo criado: {event.src_path}')

    def on_modified(self, event):
        if not event.is_directory:
            print(f'✏️  Arquivo modificado: {event.src_path}')

    def on_deleted(self, event):
        if not event.is_directory:
            print(f'🗑️  Arquivo excluído: {event.src_path}')

# Configurando monitoramento
caminho = '.'  # Diretório atual
handler = MeuHandler()
observer = Observer()
observer.schedule(handler, caminho, recursive=False)

print(f'👀 Monitorando {caminho}... Pressione Ctrl+C para parar')
observer.start()

try:
    while True:
        time.sleep(1)
except KeyboardInterrupt:
    observer.stop()
observer.join()

