from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
import uvicorn

app = FastAPI(title='API de Tarefas', version='1.0.0')

# Modelo de dados
class Tarefa(BaseModel):
    titulo: str
    descricao: str | None = None
    concluida: bool = False

# Banco de dados simulado
tarefas_db = []

@app.get('/')
def raiz():
    return {'mensagem': 'API de Tarefas funcionando!'}

@app.get('/tarefas')
def listar_tarefas():
    return {'tarefas': tarefas_db, 'total': len(tarefas_db)}

@app.post('/tarefas', status_code=201)
def criar_tarefa(tarefa: Tarefa):
    tarefa_dict = tarefa.dict()
    tarefa_dict['id'] = len(tarefas_db) + 1
    tarefas_db.append(tarefa_dict)
    return {'mensagem': 'Tarefa criada!', 'tarefa': tarefa_dict}

@app.get('/tarefas/{tarefa_id}')
def obter_tarefa(tarefa_id: int):
    for tarefa in tarefas_db:
        if tarefa['id'] == tarefa_id:
            return tarefa
    raise HTTPException(status_code=404, detail='Tarefa não encontrada')

if __name__ == '__main__':
    uvicorn.run(app, host='0.0.0.0', port=8000)

from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from pydantic import BaseModel
from typing import List
import secrets

app = FastAPI()
security = HTTPBearer()

# Credenciais simuladas
USUARIOS = {
    'admin': 'secreta123',
    'usuario': 'senha456'
}

# Modelos
class Token(BaseModel):
    access_token: str
    token_type: str

class Usuario(BaseModel):
    username: str
    email: str | None = None

# Dependência de autenticação
def validar_token(creds: HTTPAuthorizationCredentials = Depends(security)):
    token = creds.credentials
    if token != 'token_valido_123':
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail='Token inválido'
        )
    return {'usuario': 'usuario_autenticado'}

# Dependência de permissão
def verificar_admin(usuario: dict = Depends(validar_token)):
    if usuario['usuario'] != 'admin':
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail='Permissão negada'
        )
    return usuario

@app.post('/login')
def login(username: str, password: str):
    if username in USUARIOS and USUARIOS[username] == password:
        return Token(
            access_token='token_valido_123',
            token_type='bearer'
        )
    raise HTTPException(status_code=401, detail='Credenciais inválidas')

@app.get('/perfil')
def perfil(usuario: dict = Depends(validar_token)):
    return {'usuario': usuario['usuario'], 'mensagem': 'Acesso permitido'}

@app.get('/admin')
def admin_panel(admin: dict = Depends(verificar_admin)):
    return {'mensagem': 'Área administrativa', 'usuario': admin['usuario']}

# Endpoint com múltiplas dependências
@app.get('/dados-protegidos')
def dados(usuario: dict = Depends(validar_token), limite: int = 10):
    return {'usuario': usuario['usuario'], 'dados': list(range(limite))}

