from fastapi import FastAPI, WebSocket, BackgroundTasks
from fastapi.responses import JSONResponse
import asyncio
import time

app = FastAPI()

# Banco de dados simulado
processos = {}

# Tarefa em background
def processar_arquivo(nome_arquivo: str):
    time.sleep(5)  # Simula processamento longo
    processos[nome_arquivo] = 'concluído'
    print(f'✅ Arquivo {nome_arquivo} processado')

@app.post('/upload')
async def upload_arquivo(nome: str, background_tasks: BackgroundTasks):
    """Endpoint assíncrono com tarefa em background"""
    background_tasks.add_task(processar_arquivo, nome)
    processos[nome] = 'processando'
    return {
        'mensagem': 'Arquivo recebido, processando em background',
        'status': processos[nome],
        'nome': nome
    }

@app.get('/status/{nome}')
async def status_arquivo(nome: str):
    if nome not in processos:
        return JSONResponse(status_code=404, content={'erro': 'Arquivo não encontrado'})
    return {'nome': nome, 'status': processos[nome]}

# WebSocket para mensagens em tempo real
@app.websocket('/ws')
async def websocket_endpoint(websocket: WebSocket):
    await websocket.accept()
    contador = 0
    try:
        while True:
            # Recebe mensagem do cliente
            dados = await websocket.receive_text()
            print(f'Mensagem recebida: {dados}')

            # Envia resposta
            contador += 1
            await websocket.send_json({
                'resposta': f'Eco: {dados}',
                'contador': contador,
                'timestamp': time.time()
            })
    except Exception as e:
        print(f'Conexão fechada: {e}')

# Endpoint assíncrono com chamadas externas
@app.get('/busca')
async def buscar_dados(q: str):
    """Simula chamada assíncrona a API externa"""
    await asyncio.sleep(2)  # Simula latência
    return {
        'query': q,
        'resultados': [f'Resultado {i} para {q}' for i in range(5)],
        'tempo': '2s'
    }

