from loguru import logger
import sys
import time
from functools import wraps

# Configuração para este exemplo
logger.remove()
logger.add(sys.stderr, level="DEBUG", format="<green>{time:HH:mm:ss}</green> | <level>{level:8}</level> | <cyan>{message}</cyan>")
logger.add("logs/captured.log", rotation="10 MB", retention=3)

print('📝 LOGURU - CAPTURA DE EXCEÇÕES E DECORATORS\n')

# 1. Captura automática de exceções não tratadas
def capturar_excecoes_nao_tratadas():
    """Configura captura global de exceções"""
    def handle_exception(exc_type, exc_value, exc_traceback):
        logger.opt(exception=(exc_type, exc_value, exc_traceback)).error("Exceção não tratada")

    sys.excepthook = handle_exception

capturar_excecoes_nao_tratadas()

# 2. Decorator para logging automático de funções
def log_function(log_args=True, log_result=True, log_time=True):
    """Decorator que registra chamadas de função"""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start = time.time()

            # Log de entrada
            if log_args:
                args_str = f"args={args}, kwargs={kwargs}" if args or kwargs else "sem argumentos"
                logger.debug(f"Chamando {func.__name__}({args_str})")
            else:
                logger.debug(f"Chamando {func.__name__}")

            try:
                result = func(*args, **kwargs)

                # Log de saída
                elapsed = time.time() - start
                if log_time:
                    logger.debug(f"{func.__name__} executada em {elapsed:.4f}s")

                if log_result:
                    logger.debug(f"{func.__name__} retornou: {result}")
                else:
                    logger.debug(f"{func.__name__} concluída com sucesso")

                return result

            except Exception as e:
                logger.exception(f"Erro em {func.__name__}: {e}")
                raise

        return wrapper
    return decorator

# 3. Aplicando decorators
@log_function(log_args=True, log_result=True, log_time=True)
def calcular_media(numeros):
    """Calcula a média de uma lista de números"""
    if not numeros:
        raise ValueError("Lista vazia")
    return sum(numeros) / len(numeros)

@log_function(log_args=False, log_result=False, log_time=True)
def processar_dados(dados, delay=0.5):
    """Processa dados com delay simulado"""
    time.sleep(delay)
    return {"status": "ok", "processados": len(dados)}

# Executando funções com logging
try:
    print("📊 Teste 1: Função bem-sucedida")
    media = calcular_media([10, 20, 30, 40, 50])
    print(f"   Resultado: {media}\n")

    print("📊 Teste 2: Função com delay")
    resultado = processar_dados([1, 2, 3, 4, 5], delay=0.3)
    print(f"   Resultado: {resultado}\n")

    print("📊 Teste 3: Função com erro")
    media_erro = calcular_media([])
except Exception as e:
    print(f"   Exceção capturada: {e}\n")

# 4. Context manager para logging de blocos
def log_block(name):
    """Context manager para logging de blocos de código"""
    class BlockLogger:
        def __enter__(self):
            logger.info(f"🔄 Iniciando: {name}")
            self.start = time.time()
            return self

        def __exit__(self, exc_type, exc_val, exc_tb):
            elapsed = time.time() - self.start
            if exc_type:
                logger.error(f"❌ Falha em {name} após {elapsed:.2f}s")
            else:
                logger.success(f"✅ Concluído: {name} em {elapsed:.2f}s")

    return BlockLogger()

# Usando context manager
print("\n📦 Teste 4: Context manager para blocos:")
with log_block("Processamento de arquivos"):
    time.sleep(0.5)
    logger.info("Lendo arquivo...")
    time.sleep(0.3)
    logger.info("Processando dados...")
    time.sleep(0.2)

with log_block("Operação com erro"):
    try:
        time.sleep(0.2)
        raise RuntimeError("Erro simulado no processamento")
    except RuntimeError:
        logger.error("Erro capturado internamente")
        # Não re-levanta para ver o log de erro do context manager

# 5. Integração com outras bibliotecas
try:
    import requests

    # Interceptar logs de requests
    class RequestsInterceptor:
        def __init__(self, logger):
            self.logger = logger

        def send(self, request, **kwargs):
            self.logger.debug(f"🌐 Requisição: {request.method} {request.url}")
            response = requests.Session().send(request, **kwargs)
            self.logger.debug(f"📥 Resposta: {response.status_code}")
            return response

    # Aplicar interceptor
    old_send = requests.Session.send
    def new_send(self, request, **kwargs):
        logger.debug(f"Requisição: {request.method} {request.url}")
        response = old_send(self, request, **kwargs)
        logger.debug(f"Resposta: {response.status_code}")
        return response
    requests.Session.send = new_send

    print("\n🌐 Teste 5: Integração com requests:")
    response = requests.get("https://httpbin.org/status/200")

    # Restaurar
    requests.Session.send = old_send

except ImportError:
    print("⚠️ Requests não instalado, pulando integração")

# 6. Logging condicional baseado em ambiente
import os

ENV = os.getenv("APP_ENV", "development")

if ENV == "production":
    # Produção: apenas erros e críticos
    logger.remove()
    logger.add("prod.log", level="ERROR", rotation="1 day")
    logger.info("Modo produção: logs apenas de erro")
elif ENV == "staging":
    # Staging: info e acima
    logger.remove()
    logger.add("staging.log", level="INFO", rotation="1 hour")
    logger.info("Modo staging: logs de info+")
else:
    # Desenvolvimento: todos os logs com cores
    logger.info("Modo desenvolvimento: logs completos")

# 7. Métricas e contadores personalizados
class MetricsLogger:
    """Logger com métricas embutidas"""
    def __init__(self):
        self.counters = {}
        self.timers = {}

    def increment(self, name, value=1):
        self.counters[name] = self.counters.get(name, 0) + value
        logger.debug(f"📊 Métrica: {name} = {self.counters[name]}")

    def timer(self, name):
        return MetricsTimer(self, name)

    def report(self):
        logger.info(f"📈 Relatório de métricas: {self.counters}")

class MetricsTimer:
    def __init__(self, metrics, name):
        self.metrics = metrics
        self.name = name

    def __enter__(self):
        self.start = time.time()
        return self

    def __exit__(self, *args):
        elapsed = time.time() - self.start
        self.metrics.timers[self.name] = elapsed
        logger.info(f"⏱️ {self.name} levou {elapsed:.3f}s")

# Usando métricas
metrics = MetricsLogger()

with metrics.timer("processamento_dados"):
    for i in range(5):
        metrics.increment("iteracoes")
        time.sleep(0.1)

metrics.report()

print("\n✅ Demonstração concluída!")
